class CiphChatbot{constructor(){this.isOpen=false;this.conversationState="initial";this.userContext={};this.init()}init(){this.createChatbotHTML();this.attachEventListeners();this.showWelcomeMessage()}createChatbotHTML(){const e=`
      <div id="ciph-chatbot" class="ciph-chatbot">
        <div class="chatbot-toggle" id="chatbot-toggle" aria-label="Open Ciph Creative Agency Assistant Chatbot" aria-expanded="false" role="button" tabindex="0">
          <i class="bi bi-chat-dots"></i>
          <span class="notification-badge">1</span>
        </div>
        
        <div class="chatbot-window" id="chatbot-window" aria-hidden="true" role="dialog" aria-label="Chatbot Window">
          <div class="chatbot-header">
            <div class="header-content">
              <div class="avatar">
                <img src="assets/img/file.webp" alt="Ciph Creative Agency Assistant" class="avatar-img">
              </div>
              <div class="header-text">
                <h4>Ciph Creative Agency Assistant</h4>
                <span class="status">Online • Responds in minutes</span>
              </div>
            </div>
            <button class="close-btn" id="chatbot-close">
              <i class="bi bi-x-lg"></i>
            </button>
          </div>
          
          <div class="chatbot-messages" id="chatbot-messages">
            <!-- Messages will be inserted here -->
          </div>
          
          <div class="chatbot-quick-replies" id="quick-replies">
            <!-- Quick reply buttons will be inserted here -->
          </div>
          
          <div class="chatbot-input">
            <input 
              type="text" 
              id="chatbot-input-field" 
              placeholder="Type your message..."
              autocomplete="off"
            />
            <button id="chatbot-send" class="send-btn">
              <i class="bi bi-send-fill"></i>
            </button>
          </div>
        </div>
      </div>
    `;document.body.insertAdjacentHTML("beforeend",e)}attachEventListeners(){const e=document.getElementById("chatbot-toggle");const t=document.getElementById("chatbot-close");const s=document.getElementById("chatbot-send");const i=document.getElementById("chatbot-input-field");e.addEventListener("click",()=>this.toggleChatbot());e.addEventListener("keydown",e=>{if(e.key==="Enter"||e.key===" "){e.preventDefault();this.toggleChatbot()}});t.addEventListener("click",()=>this.toggleChatbot());s.addEventListener("click",()=>this.handleUserMessage());i.addEventListener("keypress",e=>{if(e.key==="Enter"){this.handleUserMessage()}})}toggleChatbot(){this.isOpen=!this.isOpen;const e=document.getElementById("chatbot-window");const t=document.getElementById("chatbot-toggle");const s=t.querySelector(".notification-badge");if(this.isOpen){e.classList.add("active");t.classList.add("active");e.setAttribute("aria-hidden","false");t.setAttribute("aria-expanded","true");if(s)s.style.display="none";setTimeout(()=>document.getElementById("chatbot-input-field").focus(),400)}else{e.classList.remove("active");t.classList.remove("active");e.setAttribute("aria-hidden","true");t.setAttribute("aria-expanded","false")}}showWelcomeMessage(){setTimeout(()=>{this.addBotMessage("Hi, I'm here to help you find the right service.\n\n"+"What brings you here today?",false);setTimeout(()=>{this.showQuickReplies([{text:"Build a Website",value:"web_dev"},{text:"Improve My Design",value:"web_design"},{text:"Grow My Business",value:"marketing"},{text:"See All Services",value:"all_services"}])},800)},1e3)}handleUserMessage(){const e=document.getElementById("chatbot-input-field");const t=e.value.trim();if(!t)return;if(this.conversationState==="awaiting_email"){this.handleEmailInput(t);e.value="";return}this.addUserMessage(t);e.value="";this.processMessage(t)}handleEmailInput(e){this.addUserMessage(e);const t=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;if(t.test(e)||e.toLowerCase()==="skip"){if(e.toLowerCase()!=="skip"){this.userContext.userEmail=e}this.showTypingIndicator();setTimeout(()=>{this.hideTypingIndicator();this.addBotMessage("Got it! Thank you. \n\nHow would you like to connect with our team?");this.showContactOptions()},800)}else{this.addBotMessage("That doesn't look like a valid email. Please try again or type 'skip' to continue.")}}showContactOptions(){this.conversationState="contact_options";this.showQuickReplies([{text:"📱 WhatsApp (Fastest)",value:"whatsapp"},{text:"📧 Email",value:"send_email"},{text:"📅 Schedule Call",value:"schedule"},{text:"❌ Close",value:"close"}])}promptForEmail(){this.conversationState="awaiting_email";this.showTypingIndicator();setTimeout(()=>{this.hideTypingIndicator();this.addBotMessage("Perfect! Before we connect, could you please share your **email address**?\n\n"+"This helps us follow up with you quickly. (Or type 'skip')")},800)}processMessage(e){const t=e.toLowerCase();this.showTypingIndicator();setTimeout(()=>{this.hideTypingIndicator();if(t.includes("web dev")||t.includes("development")||t.includes("software")||t.includes("backend")||t.includes("frontend")){this.handleWebDevelopment()}else if(t.includes("web design")||t.includes("design")||t.includes("ui")||t.includes("ux")||t.includes("responsive")){this.userContext.lastSelectionText="Web Design";this.handleWebDesign()}else if(t.includes("marketing")||t.includes("seo")||t.includes("digital")||t.includes("campaign")){this.userContext.lastSelectionText="Digital Marketing";this.handleMarketing()}else if(t.includes("graphic")||t.includes("branding")||t.includes("logo")){this.userContext.lastSelectionText="Graphic Design";this.handleGraphicDesign()}else if(t.includes("product")||t.includes("management")||t.includes("strategy")){this.userContext.lastSelectionText="Product Management";this.handleProductManagement()}else if(t.includes("microsoft")||t.includes("365")||t.includes("office")){this.userContext.lastSelectionText="Microsoft 365";this.handleMicrosoft365()}else if(t.includes("ecommerce")||t.includes("e-commerce")||t.includes("shop")||t.includes("store")){this.handleEcommerce()}else if(t.includes("pwa")||t.includes("progressive")||t.includes("app")){this.handlePWA()}else if(t.includes("all services")||t.includes("services")||t.includes("what do you")){this.handleAllServices()}else if(t.includes("more services")){this.handleMoreServices()}else if(t.includes("price")||t.includes("cost")||t.includes("quote")||t.includes("budget")){this.handlePricingInquiry()}else if(t.includes("contact")||t.includes("call")||t.includes("phone")||t.includes("email")){this.handleContactInquiry()}else if(t.includes("portfolio")||t.includes("work")||t.includes("projects")||t.includes("examples")){this.handlePortfolio()}else if(t.includes("hello")||t.includes("hi")||t.includes("hey")){this.handleGreeting()}else if(t.includes("thank")||t.includes("thanks")||t.includes("bye")||t.includes("goodbye")){this.closeConversation()}else{this.handleUnknownQuery(e)}},1500)}handleWebDevelopment(){this.conversationState="web_dev";this.addBotMessage("Great, I can help you build a website. 💻\n\n"+"What type of website do you need?");setTimeout(()=>{this.showQuickReplies([{text:"Business Website",value:"business_website"},{text:"Online Store",value:"ecommerce"},{text:"Custom Solution",value:"custom_solution"},{text:"Not Sure Yet",value:"consultation"}])},800)}handleWebDesign(){this.conversationState="web_design";this.addBotMessage("Perfect, Let's improve your design. 🎨\n\n"+"What do you need help with?");setTimeout(()=>{this.showQuickReplies([{text:"New Design",value:"new_design"},{text:"Redesign Current Site",value:"redesign"},{text:"Logo & Branding",value:"branding"},{text:"Talk to Designer",value:"expert"}])},800)}handleMarketing(){this.conversationState="marketing";this.addBotMessage("Excellent, Let's grow your business. 📈\n\n"+"What's your main goal?");setTimeout(()=>{this.showQuickReplies([{text:"Get More Customers",value:"get_customers"},{text:"Improve SEO",value:"seo"},{text:"Social Media Help",value:"social_media"},{text:"Full Marketing Plan",value:"full_marketing"}])},800)}handleGraphicDesign(){this.conversationState="graphic";this.addBotMessage("Awesome, 🎨 Our Graphic Design services include:\n\n"+"✅ Business Branding\n"+"✅ Logo Design\n"+"✅ Marketing Materials\n"+"✅ Social Media Graphics\n"+"✅ Brand Identity\n"+"✅ Print Design\n\n"+"We create visuals that make your brand memorable!");setTimeout(()=>{this.addBotMessage("What do you need designed?");this.showQuickReplies([{text:"Logo & Branding",value:"branding"},{text:"Marketing Materials",value:"marketing_materials"},{text:"Social Graphics",value:"social_graphics"},{text:"Get Started",value:"get_started"},{text:"❌ Close",value:"close"}])},1e3)}handleProductManagement(){this.conversationState="product";this.addBotMessage("Excellent, 💼 Our Product Management services help you:\n\n"+"✅ Define Product Strategy\n"+"✅ Create Roadmaps\n"+"✅ Validate Ideas\n"+"✅ Prioritize Features\n"+"✅ Improve Product-Market Fit\n"+"✅ Drive Growth\n\n"+"We turn ideas into successful products!");setTimeout(()=>{this.addBotMessage("Where are you in your product journey?");this.showQuickReplies([{text:"New Product Idea",value:"new_product"},{text:"Existing Product",value:"existing_product"},{text:"Need Strategy",value:"strategy"},{text:"Talk to Expert",value:"expert"},{text:"❌ Close",value:"close"}])},1e3)}handleMicrosoft365(){this.conversationState="microsoft";this.addBotMessage("Great, Our Microsoft 365 Support includes:\n\n"+"✅ Setup & Configuration\n"+"✅ Migration Services\n"+"✅ Training & Support\n"+"✅ Security Setup\n"+"✅ Ongoing Maintenance\n"+"✅ Troubleshooting\n\n"+"We help teams work efficiently with Microsoft 365!");setTimeout(()=>{this.addBotMessage("What do you need help with?");this.showQuickReplies([{text:"New Setup",value:"m365_setup"},{text:"Migration",value:"m365_migration"},{text:"Support",value:"m365_support"},{text:"Contact Us",value:"contact"},{text:"❌ Close",value:"close"}])},1e3)}handleEcommerce(){this.conversationState="ecommerce";this.addBotMessage("Perfect for online selling, 🛒 Our E-commerce solutions include:\n\n"+"✅ Custom Online Stores\n"+"✅ Payment Gateway Integration\n"+"✅ Inventory Management\n"+"✅ Shopping Cart Development\n"+"✅ Mobile Commerce\n"+"✅ SEO for E-commerce\n\n"+"We build stores that drive sales!");setTimeout(()=>{this.addBotMessage("What platform are you interested in?");this.showQuickReplies([{text:"Custom Solution",value:"custom_ecommerce"},{text:"Shopify",value:"shopify"},{text:"WooCommerce",value:"woocommerce"},{text:"Not Sure",value:"ecommerce_help"},{text:"❌ Close",value:"close"}])},1e3)}handlePWA(){this.conversationState="pwa";this.addBotMessage("Excellent choice, 📱 Progressive Web Apps offer:\n\n"+"✅ App-like Experience\n"+"✅ Works Offline\n"+"✅ Fast Loading\n"+"✅ Push Notifications\n"+"✅ Installable on Devices\n"+"✅ Cross-Platform\n\n"+"PWAs combine the best of web and mobile apps!");setTimeout(()=>{this.addBotMessage("Want to learn more or get started?");this.showQuickReplies([{text:"Learn More",value:"pwa_info"},{text:"Get a Quote",value:"quote"},{text:"See Examples",value:"portfolio"},{text:"Talk to Expert",value:"expert"},{text:"❌ Close",value:"close"}])},1e3)}handleAllServices(){this.addBotMessage("Here's what we do best! 🌟\n\n"+"🌐 Website Development\n"+"🎨 Design & Branding\n"+"📱 Digital Marketing\n"+"🛒 E-commerce Stores\n"+"☁️ Microsoft 365 Support\n\n"+"What interests you?");setTimeout(()=>{this.showQuickReplies([{text:"Build Website",value:"web_dev"},{text:"Design Help",value:"web_design"},{text:"Marketing",value:"marketing"},{text:"Talk to Us",value:"consultation"}])},1e3)}handlePricingInquiry(){this.addBotMessage("Great question, 💰\n\n"+"Our pricing is customized based on your specific needs. We offer:\n\n"+"✅ Flexible payment plans\n"+"✅ Competitive rates for East Africa\n"+"✅ No hidden fees\n"+"✅ FREE consultation\n"+"✅ Custom quotes within 24 hours\n\n"+"Every project is unique, so let's discuss your requirements!");setTimeout(()=>{this.addBotMessage("Would you like to:");this.showQuickReplies([{text:"Get a Quote",value:"quote"},{text:"Schedule Call",value:"schedule"},{text:"View Services",value:"all_services"},{text:"Contact Us",value:"contact"}])},1500)}handlePortfolio(){this.addBotMessage("Check out our work, 🎨\n\n"+"We've completed 5,000+ successful campaigns and projects across:\n\n"+"✅ Web Development\n"+"✅ E-commerce Stores\n"+"✅ Branding Projects\n"+"✅ Marketing Campaigns\n"+"✅ Progressive Web Apps\n\n"+"Visit our portfolio page to see case studies and results!");setTimeout(()=>{this.showQuickReplies([{text:"👀 View Portfolio",value:"view_portfolio"},{text:"📞 Discuss My Project",value:"contact"},{text:"🔙 Back to Services",value:"all_services"}])},1e3)}handleContactInquiry(){this.addBotMessage("Let's connect! 📞\n\n"+"📧 Email: ciphcreativeagency@gmail.com\n"+"📱 Phone/WhatsApp: +256 393 24 2000\n"+"🌐 Website: https://ciphca.com\n"+"📍 Location: Upper Kauga, Mukono, Uganda\n\n"+"⏰ Hours:\n"+"Sun-Fri: 9 AM - 6 PM\n"+"Sat: 9 AM - 4 PM\n\n"+"We respond within 2 hours! 🚀");setTimeout(()=>{this.showQuickReplies([{text:"📧 Send Email",value:"send_email"},{text:"📱 WhatsApp Us",value:"whatsapp"},{text:"📅 Schedule Meeting",value:"schedule"},{text:"❌ Close Chat",value:"close"}])},1e3)}handleGreeting(){this.addBotMessage("Hello, Welcome to Ciph Creative Agency!\n\n"+"We're a leading digital agency in East Africa (Uganda, Kenya, Tanzania, Rwanda) specializing in:\n\n"+"🌐 Web Development & Design\n"+"📱 Digital Marketing\n"+"🎨 Branding & Graphics\n"+"💼 Product Management\n\n"+"How can we help your business grow?");setTimeout(()=>{this.showMainMenu()},1200)}handleUnknownQuery(e){this.addBotMessage("I want to make sure I understand you correctly! 🤔\n\n"+"I can help you with:\n\n"+"🌐 Web Development\n"+"🎨 Web Design\n"+"📱 Digital Marketing\n"+"🖼️ Graphic Design\n"+"💼 Product Management\n"+"☁️ Microsoft 365\n"+"🛒 E-commerce\n\n"+"Which service are you interested in?");setTimeout(()=>{this.showMainMenu()},800)}showMainMenu(){this.showQuickReplies([{text:"🌐 Web Development",value:"web_dev"},{text:"🎨 Web Design",value:"web_design"},{text:"📱 Marketing",value:"marketing"},{text:"💼 All Services",value:"all_services"}])}handleMoreServices(){this.addBotMessage("Here are more services we offer! 🎯\n\n"+"🖼️ Graphic Design & Branding\n"+"💼 Product Management\n"+"☁️ Microsoft 365 Support\n"+"🛒 E-commerce Solutions\n"+"📲 Progressive Web Apps\n"+"🔧 Website Maintenance\n\n"+"Which one interests you?");setTimeout(()=>{this.showQuickReplies([{text:"🖼️ Graphic Design",value:"graphic"},{text:"💼 Product Mgmt",value:"product"},{text:"☁️ Microsoft 365",value:"microsoft"},{text:"🛒 E-commerce",value:"ecommerce"},{text:"❌ Close",value:"close"}])},1e3)}handleQuickReply(e){if(e==="send_email"){const t=this.userContext.lastSelectionText||"your services";const s=encodeURIComponent(`Inquiry: ${t}`);const i=encodeURIComponent(`Hi Ciph Team,\n\nI'm interested in ${t}. Please get back to me with more information.\n\nThank you.`);window.location.href=`mailto:ciphcreativeagency@gmail.com?subject=${s}&body=${i}`;this.addBotMessage("Opening your email client... 📧\n\n"+"We'll respond within 2 hours during business hours!");setTimeout(()=>{this.closeConversation()},2e3)}else if(e==="whatsapp"){const t=this.userContext.lastSelectionText||"your services";const n=this.userContext.userEmail?` (Email: ${this.userContext.userEmail})`:"";const o=encodeURIComponent(`Hi, I'm interested in ${t}!${n}`);window.open(`https://wa.me/256393242000?text=${o}`,"_blank");this.addBotMessage("Opening WhatsApp... 💬\n\n"+"Our team will respond to you shortly!");setTimeout(()=>{this.closeConversation()},2e3)}else if(e==="schedule"){const a=document.getElementById("calendlyModal");if(a&&typeof bootstrap!=="undefined"){const l=new bootstrap.Modal(a);l.show()}else{window.open("https://calendly.com/ciphcreativeagency/30min","_blank")}this.addBotMessage("Opening our calendar... 📅\n\n"+"Pick a time that works best for you!");setTimeout(()=>{this.closeConversation()},2e3)}else if(e==="business_website"||e==="custom_solution"||e==="new_design"||e==="redesign"||e==="branding"||e==="get_customers"||e==="seo"||e==="social_media"||e==="full_marketing"||e==="ecommerce"||e==="consultation"||e==="expert"||e==="quote"){this.promptForEmail()}else if(e==="consultation"||e==="expert"){this.addBotMessage("Smart move! Let's schedule a FREE consultation. 🎯\n\n"+"We'll discuss:\n"+"✅ Your goals\n"+"✅ Best solutions\n"+"✅ Timeline & budget\n"+"✅ Next steps\n\n"+"Choose your preferred way to connect:");setTimeout(()=>{this.showQuickReplies([{text:"📅 Book a Call",value:"schedule"},{text:"📱 WhatsApp Chat",value:"whatsapp"},{text:"📧 Email Instead",value:"send_email"}])},1e3)}else if(e==="portfolio"||e==="view_portfolio"){window.open("https://ciphca.com/portfolio-details.html","_blank");this.addBotMessage("Opening our portfolio... 🎨\n\n"+"Check out our work!");setTimeout(()=>{this.addBotMessage("Like what you see?");this.showQuickReplies([{text:"✅ Yes, Let's Talk",value:"consultation"},{text:"🔙 See Services",value:"all_services"},{text:"❌ Close",value:"close"}])},2e3)}else if(e==="all_services"){this.handleAllServices()}else if(e==="more_services"){this.handleMoreServices()}else if(e==="contact"){this.handleContactInquiry()}else if(e==="close"){this.closeConversation()}else if(e==="restart"){this.restartConversation()}else{this.processMessage(e)}}closeConversation(){this.addBotMessage("Thank you for chatting with us 🙏\n\n"+"We're excited to help your business grow!\n\n"+"If you have any more questions, feel free to:\n"+"📧 Email: ciphcreativeagency@gmail.com\n"+"📱 Call/WhatsApp: +256 393 24 2000\n\n"+"Have a wonderful day! ✨");setTimeout(()=>{this.showQuickReplies([{text:"🔄 Start New Chat",value:"restart"},{text:"📱 Contact Us",value:"contact"}])},1500)}restartConversation(){this.conversationState="initial";this.userContext={};const e=document.getElementById("chatbot-messages");e.innerHTML="";const t=document.getElementById("quick-replies");t.innerHTML="";this.addBotMessage("Welcome back\n\n"+"How can I help you today?");setTimeout(()=>{this.showMainMenu()},800)}addUserMessage(e){const t=document.getElementById("chatbot-messages");const s=`
      <div class="message user-message">
        <div class="message-content">${this.escapeHtml(e)}</div>
      </div>
    `;t.insertAdjacentHTML("beforeend",s);this.scrollToBottom()}addBotMessage(e,t=true){const s=document.getElementById("chatbot-messages");const i=e.replace(/\n/g,"<br>");const n=`
      <div class="message bot-message">
        ${t?'<div class="message-avatar"><img src="assets/img/file.webp" alt="Bot" class="avatar-img"></div>':""}
        <div class="message-content">${i}</div>
      </div>
    `;s.insertAdjacentHTML("beforeend",n);this.scrollToBottom();if(!this.isOpen){const o=document.getElementById("chatbot-toggle");o.style.animation="none";o.offsetHeight;o.style.animation="pulse 1s 2"}}showTypingIndicator(){const e=document.getElementById("chatbot-messages");const t=`
      <div class="message bot-message typing-indicator" id="typing-indicator">
        <div class="message-avatar"><img src="assets/img/file.webp" alt="Bot" class="avatar-img"></div>
        <div class="typing-dots">
          <span></span>
          <span></span>
          <span></span>
        </div>
      </div>
    `;e.insertAdjacentHTML("beforeend",t);this.scrollToBottom()}hideTypingIndicator(){const e=document.getElementById("typing-indicator");if(e){e.remove()}}showQuickReplies(e){const s=document.getElementById("quick-replies");s.innerHTML="";e.forEach(e=>{const t=document.createElement("button");t.className="quick-reply-btn";t.textContent=e.text;t.addEventListener("click",()=>{if(e.value!=="whatsapp"&&e.value!=="send_email"&&e.value!=="schedule"){this.userContext.lastSelectionText=e.text}this.addUserMessage(e.text);s.innerHTML="";this.handleQuickReply(e.value)});s.appendChild(t)})}scrollToBottom(){const e=document.getElementById("chatbot-messages");e.scrollTop=e.scrollHeight}escapeHtml(e){const t=document.createElement("div");t.textContent=e;return t.innerHTML}}document.addEventListener("DOMContentLoaded",()=>{new CiphChatbot});